334	func groupExecutionCleanupAttemptProcesses(processes []executionCleanupAttemptProcess) []executionCleanupAttemptProcessGroup {
335		if len(processes) == 0 {
336			return nil
337		}
338		buckets := make(map[int][]executionCleanupAttemptProcess, len(processes))
339		for _, proc := range processes {
340			if proc.PID <= 0 || proc.PID == os.Getpid() {
341				continue
342			}
343			groupID := proc.PGID
344			if groupID <= 0 {
345				groupID = proc.PID
346			}
347			buckets[groupID] = append(buckets[groupID], proc)
348		}
349		if len(buckets) == 0 {
350			return nil
351		}
352	
353		groups := make([]executionCleanupAttemptProcessGroup, 0, len(buckets))
354		for groupID, members := range buckets {
355			sort.Slice(members, func(i, j int) bool {
356				if members[i].PID == members[j].PID {
357					return members[i].Command < members[j].Command
358				}
359				return members[i].PID < members[j].PID
360			})
361			groups = append(groups, executionCleanupAttemptProcessGroup{
362				GroupID: groupID,
363				Members: members,
364			})
365		}
366		sort.Slice(groups, func(i, j int) bool {
367			if groups[i].GroupID == groups[j].GroupID {
368				return pickExecutionCleanupAttemptRepresentative(groups[i].Members).PID < pickExecutionCleanupAttemptRepresentative(groups[j].Members).PID
369			}
370			return groups[i].GroupID < groups[j].GroupID
371		})
372		return groups
373	}
